import SwiftUI
import AppKit

class AppDelegate: NSObject, NSApplicationDelegate {
    private var statusItem: NSStatusItem!
    private var popover: NSPopover!
    private let monitors = MonitorCoordinator.shared
    private let settings = AppSettings.shared
    private let historyStore = HistoryStore.shared
    private var menuBarController: MenuBarController!
    private var alertRulesEngine: AlertRulesEngine?
    private var lowBatteryAlertTimer: Timer?
    private var lowBatteryAlertShown = false
    private var batteryAutomationTimer: Timer?
    private var batterySettingsOpenedAt: Date?

    func applicationDidFinishLaunching(_ notification: Notification) {
        NSApp.setActivationPolicy(.accessory)
        monitors.setPowerSaveMode(settings.powerSaveModeActive)

        // Start monitoring
        monitors.startAll()
        historyStore.start(with: monitors)

        // Create status item
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)

        if let button = statusItem.button {
            button.action = #selector(handleStatusItemClick(_:))
            button.target = self
            button.sendAction(on: [.leftMouseUp, .rightMouseUp])
        }

        // Create and start menu bar controller
        menuBarController = MenuBarController(statusItem: statusItem, monitors: monitors)
        menuBarController.startUpdating()

        startAlertRulesEngine()
        startLowBatteryAlertMonitoring()
        startBatteryAutomationMonitoring()

        // Create popover
        popover = NSPopover()
        popover.contentSize = NSSize(width: 360, height: 520)
        popover.behavior = .transient
        popover.contentViewController = NSHostingController(
            rootView: DashboardView(monitors: monitors, historyStore: historyStore)
        )
    }

    func applicationWillTerminate(_ notification: Notification) {
        alertRulesEngine?.stop()
        alertRulesEngine = nil
        lowBatteryAlertTimer?.invalidate()
        lowBatteryAlertTimer = nil
        batteryAutomationTimer?.invalidate()
        batteryAutomationTimer = nil
        historyStore.stop()
        menuBarController.stopUpdating()
        monitors.stopAll()
    }

    @objc private func handleStatusItemClick(_ sender: NSStatusBarButton) {
        guard let event = NSApp.currentEvent else {
            togglePopover()
            return
        }

        switch event.type {
        case .rightMouseUp:
            popover.performClose(nil)
            statusItem.menu = statusMenu()
            sender.performClick(nil)
            statusItem.menu = nil
        default:
            togglePopover()
        }
    }

    @objc func togglePopover() {
        guard let button = statusItem.button else { return }

        if popover.isShown {
            popover.performClose(nil)
        } else {
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
        }
    }

    private func statusMenu() -> NSMenu {
        let menu = NSMenu()
        menu.addItem(
            withTitle: "Open WhatTheLoad",
            action: #selector(openDashboardFromMenu),
            keyEquivalent: ""
        )
        menu.addItem(.separator())
        menu.addItem(
            withTitle: "Quit WhatTheLoad",
            action: #selector(quitApplication),
            keyEquivalent: "q"
        )
        menu.items.forEach { $0.target = self }
        return menu
    }

    @objc private func openDashboardFromMenu() {
        if !popover.isShown {
            togglePopover()
        }
    }

    @objc private func quitApplication() {
        NSApp.terminate(nil)
    }

    private func startLowBatteryAlertMonitoring() {
        lowBatteryAlertTimer?.invalidate()
        lowBatteryAlertTimer = Timer.scheduledTimer(withTimeInterval: 15.0, repeats: true) { [weak self] _ in
            self?.checkLowBatteryAlert()
        }
        checkLowBatteryAlert()
    }

    private func startAlertRulesEngine() {
        let engine = AlertRulesEngine(
            monitors: monitors,
            historyStore: historyStore,
            settings: settings
        )
        engine.onAlert = { [weak self] severity, title, message in
            guard title != "Low Battery" else { return }
            guard self?.settings.alertPopupsEnabled == true else { return }
            self?.showBlockingAlert(severity: severity, title: title, message: message)
        }
        engine.start()
        alertRulesEngine = engine
    }

    private func startBatteryAutomationMonitoring() {
        batteryAutomationTimer?.invalidate()
        batteryAutomationTimer = Timer.scheduledTimer(withTimeInterval: 20.0, repeats: true) { [weak self] _ in
            self?.evaluateBatteryAutomation()
        }
        evaluateBatteryAutomation()
    }

    private func checkLowBatteryAlert() {
        guard settings.lowBatteryAlertsEnabled else {
            lowBatteryAlertShown = false
            return
        }

        guard let metrics = monitors.battery.current else { return }

        let threshold = settings.lowBatteryAlertThreshold
        let isDischargingOnBattery = metrics.powerSource == .battery && !metrics.isCharging

        if isDischargingOnBattery && metrics.chargePercent <= threshold {
            guard !lowBatteryAlertShown else { return }
            lowBatteryAlertShown = true
            showLowBatteryAlert(metrics: metrics, threshold: threshold)
            return
        }

        let hasRecovered = metrics.isCharging || metrics.powerSource != .battery || metrics.chargePercent >= (threshold + 5)
        if hasRecovered {
            lowBatteryAlertShown = false
        }
    }

    private func evaluateBatteryAutomation() {
        guard settings.batteryAutomationEnabled else {
            if settings.powerSaveModeActive {
                setPowerSaveMode(false, reason: "Low battery automation disabled.")
            }
            return
        }

        guard let metrics = monitors.battery.current else { return }
        let threshold = settings.batteryAutomationThreshold

        let shouldEnable = metrics.powerSource == .battery &&
            !metrics.isCharging &&
            metrics.chargePercent <= threshold
        let shouldDisable = metrics.isCharging ||
            metrics.powerSource != .battery ||
            metrics.chargePercent >= (threshold + 5)

        if shouldEnable && !settings.powerSaveModeActive {
            setPowerSaveMode(true, reason: String(format: "Battery reached %.0f%%.", metrics.chargePercent))
            if settings.batteryAutomationAutoOpenSettings {
                openBatterySettingsIfNeeded()
            }
        } else if shouldDisable && settings.powerSaveModeActive {
            setPowerSaveMode(false, reason: "Battery state recovered.")
        }
    }

    private func setPowerSaveMode(_ enabled: Bool, reason: String) {
        settings.powerSaveModeActive = enabled
        monitors.setPowerSaveMode(enabled)
        historyStore.recordEvent(TimelineEvent(
            severity: .info,
            category: .battery,
            title: enabled ? "Power Save Mode Enabled" : "Power Save Mode Disabled",
            message: reason
        ))
    }

    private func openBatterySettingsIfNeeded() {
        let now = Date()
        if let lastOpened = batterySettingsOpenedAt, now.timeIntervalSince(lastOpened) < 1800 {
            return
        }
        batterySettingsOpenedAt = now

        let urls = [
            "x-apple.systempreferences:com.apple.preference.battery",
            "x-apple.systempreferences:com.apple.Battery-Settings.extension"
        ]

        for rawURL in urls {
            guard let url = URL(string: rawURL) else { continue }
            if NSWorkspace.shared.open(url) {
                return
            }
        }
    }

    private func showLowBatteryAlert(metrics: BatteryMetrics, threshold: Double) {
        let levelText = String(format: "%.0f", metrics.chargePercent)
        let thresholdText = String(format: "%.0f", threshold)

        var details = "Battery level is \(levelText)% (threshold \(thresholdText)%)."
        if let remaining = metrics.timeRemaining {
            details += "\nEstimated time remaining: \(formatRemainingTime(remaining))."
        }
        details += "\nPlug in your charger soon."

        NSApp.activate(ignoringOtherApps: true)

        let alert = NSAlert()
        alert.alertStyle = .warning
        alert.messageText = "Low Battery"
        alert.informativeText = details
        alert.addButton(withTitle: "Dismiss")
        alert.runModal()
    }

    private func showBlockingAlert(severity: TimelineSeverity, title: String, message: String) {
        DispatchQueue.main.async {
            NSApp.activate(ignoringOtherApps: true)

            let alert = NSAlert()
            alert.alertStyle = (severity == .critical) ? .critical : .warning
            alert.messageText = title
            alert.informativeText = message
            alert.addButton(withTitle: "Dismiss")
            alert.runModal()
        }
    }

    private func formatRemainingTime(_ seconds: TimeInterval) -> String {
        let totalMinutes = max(0, Int(seconds / 60))
        let hours = totalMinutes / 60
        let minutes = totalMinutes % 60

        if hours > 0 {
            return "\(hours)h \(minutes)m"
        }
        return "\(minutes)m"
    }
}

import SwiftUI
import ServiceManagement

struct SettingsView: View {
    let monitors: MonitorCoordinator
    let historyStore: HistoryStore

    @ObservedObject private var settings = AppSettings.shared
    @Environment(\.dismiss) var dismiss

    init(
        monitors: MonitorCoordinator = .shared,
        historyStore: HistoryStore = .shared
    ) {
        self.monitors = monitors
        self.historyStore = historyStore
    }

    var body: some View {
        VStack(spacing: 0) {
            HStack {
                Text("Settings")
                    .font(.system(size: 16, weight: .semibold))

                Spacer()

                Button("Done") {
                    dismiss()
                }
                .buttonStyle(.plain)
                .foregroundColor(.blue)
            }
            .padding(16)

            Divider()

            ScrollView {
                VStack(alignment: .leading, spacing: 20) {
                    pollIntervalsSection
                    divider
                    menuBarSection
                    divider
                    alertsSection
                    divider
                    batteryAutomationSection
                    divider
                    diagnosticsSection
                    divider
                    systemSection
                }
                .padding(16)
            }
        }
        .frame(width: 360, height: 520)
        .background(Color(NSColor.windowBackgroundColor))
    }

    private var pollIntervalsSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "POLL INTERVALS")

            SliderRow(title: "CPU", value: $settings.cpuPollInterval, range: 0.5...10, unit: "s")
            SliderRow(title: "Memory", value: $settings.memoryPollInterval, range: 1...30, unit: "s")
            SliderRow(title: "Network", value: $settings.networkPollInterval, range: 0.5...10, unit: "s")
            SliderRow(title: "Wi-Fi", value: $settings.wifiPollInterval, range: 0.5...10, unit: "s")
            SliderRow(title: "Disk", value: $settings.diskPollInterval, range: 1...60, unit: "s")
            SliderRow(title: "Processes", value: $settings.processesPollInterval, range: 1...30, unit: "s")
            SliderRow(title: "Battery", value: $settings.batteryPollInterval, range: 5...120, unit: "s")

            Button("Apply Polling Changes") {
                monitors.restartAll()
            }
            .buttonStyle(.bordered)
            .controlSize(.small)
        }
    }

    private var menuBarSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "MENU BAR")

            Toggle("Show Sparkline", isOn: $settings.showMenuBarSparkline)
                .font(.system(size: 12))

            Toggle("Show Network Speed", isOn: $settings.showMenuBarNetworkText)
                .font(.system(size: 12))

            Picker("Sparkline Metric", selection: $settings.menuBarSparklineMetric) {
                Text("CPU").tag("cpu")
                Text("Memory").tag("memory")
                Text("Network").tag("network")
            }
            .pickerStyle(.segmented)
            .font(.system(size: 11))
        }
    }

    private var alertsSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "ALERTS")

            Toggle("Enable Alerts", isOn: $settings.alertsEnabled)
                .font(.system(size: 12))

            if settings.alertsEnabled {
                SliderRow(title: "Cooldown", value: $settings.alertsCooldownMinutes, range: 1...60, unit: "m")

                Toggle("Quiet Hours", isOn: $settings.alertsQuietHoursEnabled)
                    .font(.system(size: 12))

                if settings.alertsQuietHoursEnabled {
                    HourPickerRow(title: "Start", value: $settings.alertsQuietHoursStartHour)
                    HourPickerRow(title: "End", value: $settings.alertsQuietHoursEndHour)
                }

                SliderRow(title: "CPU %", value: $settings.cpuUsageAlertThreshold, range: 50...100, unit: "%")
                SliderRow(title: "CPU Temp", value: $settings.cpuTempAlertThreshold, range: 60...110, unit: "°C")
                SliderRow(title: "Packet Loss", value: $settings.packetLossAlertThreshold, range: 1...20, unit: "%")
                SliderRow(title: "Jitter", value: $settings.jitterAlertThreshold, range: 5...150, unit: "ms")
                SliderRow(title: "Low Disk", value: $settings.lowDiskFreePercentThreshold, range: 2...30, unit: "%")
            }

            Toggle("Low Battery Popup", isOn: $settings.lowBatteryAlertsEnabled)
                .font(.system(size: 12))

            if settings.lowBatteryAlertsEnabled {
                SliderRow(title: "Battery Alert", value: $settings.lowBatteryAlertThreshold, range: 5...50, unit: "%")
            }
        }
    }

    private var batteryAutomationSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "BATTERY AUTOMATION")

            Toggle("Enable Low Battery Automation", isOn: $settings.batteryAutomationEnabled)
                .font(.system(size: 12))

            if settings.batteryAutomationEnabled {
                SliderRow(title: "Automation Threshold", value: $settings.batteryAutomationThreshold, range: 5...60, unit: "%")

                Toggle("Auto-open Battery Settings", isOn: $settings.batteryAutomationAutoOpenSettings)
                    .font(.system(size: 12))
            }

            HStack {
                Text("Power Save Mode")
                    .font(.system(size: 11, design: .monospaced))
                    .foregroundColor(.secondary)

                Spacer()

                Text(settings.powerSaveModeActive ? "Active" : "Inactive")
                    .font(.system(size: 11, weight: .semibold, design: .monospaced))
                    .foregroundColor(settings.powerSaveModeActive ? .orange : .secondary)
            }
        }
    }

    private var diagnosticsSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "DIAGNOSTICS")

            Button("Export Diagnostics Bundle") {
                DiagnosticsExporter.export(monitors: monitors, historyStore: historyStore, settings: settings)
            }
            .buttonStyle(.bordered)
            .controlSize(.small)

            if !settings.lastDiagnosticsExportStatus.isEmpty {
                Text(settings.lastDiagnosticsExportStatus)
                    .font(.system(size: 10))
                    .foregroundColor(.secondary)
                    .fixedSize(horizontal: false, vertical: true)
            }
        }
    }

    private var systemSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionHeader(title: "SYSTEM")

            Toggle("Launch at Login", isOn: $settings.launchAtLogin)
                .font(.system(size: 12))
                .onChange(of: settings.launchAtLogin) { _, newValue in
                    toggleLaunchAtLogin(enabled: newValue)
                }

            Button("Reset to Defaults") {
                settings.resetToDefaults()
                monitors.setPowerSaveMode(false)
                monitors.restartAll()
            }
            .buttonStyle(.plain)
            .foregroundColor(.red)
            .font(.system(size: 12))
        }
    }

    private var divider: some View {
        Divider().padding(.vertical, 4)
    }

    private func toggleLaunchAtLogin(enabled: Bool) {
        if #available(macOS 13.0, *) {
            do {
                if enabled {
                    try SMAppService.mainApp.register()
                } else {
                    try SMAppService.mainApp.unregister()
                }
            } catch {
                print("Failed to \(enabled ? "enable" : "disable") launch at login: \(error)")
            }
        }
    }
}

struct SectionHeader: View {
    let title: String

    var body: some View {
        Text(title)
            .font(.system(size: 11, weight: .semibold, design: .monospaced))
            .foregroundColor(.secondary)
            .tracking(0.5)
    }
}

struct SliderRow: View {
