                .foregroundColor(.primary)

            Spacer()

            Picker(title, selection: Binding(
                get: { Int(value) },
                set: { value = Double($0) }
            )) {
                ForEach(0..<24, id: \.self) { hour in
                    Text(String(format: "%02d:00", hour)).tag(hour)
                }
            }
            .frame(width: 110)
        }
    }
}

